namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 4;
    private readonly List<NotificationItem> _all =
    [
        new() { Id = 1, Message = "Welcome to NotificationsApp!", Timestamp = DateTime.UtcNow.AddMinutes(-30) },
        new() { Id = 2, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-15) },
        new() { Id = 3, Message = "New comment on your post.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
    ];

    public Task<List<NotificationItem>> GetInitialNotificationsAsync()
    {
        lock (_all)
        {
            return Task.FromResult(_all.ToList());
        }
    }

    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastSeenId)
    {
        // Simulate new notifications arriving occasionally
        lock (_all)
        {
            if (Random.Shared.NextDouble() < 0.3)
            {
                _all.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = $"New event at {DateTime.UtcNow:T}",
                    Timestamp = DateTime.UtcNow,
                });
            }

            var newer = _all.Where(n => n.Id > lastSeenId).ToList();
            return Task.FromResult(newer);
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService Svc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (items is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@items.Count</span>
    }
</h1>

@if (items is null)
{
    <p><em>Loading…</em></p>
}
else if (items.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in items.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? items { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we only fetch when state wasn't restored from prerender
        items ??= await Svc.GetInitialNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender is never called during prerender —
        // polling only starts once the page is live and interactive.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var lastId = items?.Count > 0 ? items.Max(n => n.Id) : 0;
            var newer = await Svc.GetNotificationsSinceAsync(lastId);

            if (newer.Count > 0)
            {
                items ??= [];
                items.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

