namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 4;
    private readonly List<NotificationItem> _all =
    [
        new() { Id = 1, Message = "Welcome to NotificationsApp!", Timestamp = DateTime.UtcNow.AddMinutes(-30) },
        new() { Id = 2, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-15) },
        new() { Id = 3, Message = "New comment on your post.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
    ];

    public Task<List<NotificationItem>> GetInitialNotificationsAsync()
    {
        lock (_all)
        {
            return Task.FromResult(_all.ToList());
        }
    }

    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastSeenId)
    {
        // Simulate new notifications arriving occasionally
        lock (_all)
        {
            if (Random.Shared.NextDouble() < 0.3)
            {
                _all.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = $"New event at {DateTime.UtcNow:T}",
                    Timestamp = DateTime.UtcNow,
                });
            }

            var newer = _all.Where(n => n.Id > lastSeenId).ToList();
            return Task.FromResult(newer);
        }
    }
}

